import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.Scanner;

public class SecurePathTraversal {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("Enter a file name:");
        String fileName = scanner.nextLine();

        // Validate and sanitize user input to prevent path traversal
        Path filePath = Paths.get("/path/to/directory").resolve(fileName).normalize();

        if (!filePath.startsWith(Paths.get("/path/to/directory"))) {
            System.out.println("Invalid file path");
            return;
        }

        try {
            byte[] fileContent = Files.readAllBytes(filePath);
            System.out.println(new String(fileContent));
        } catch (IOException e) {
            System.out.println("Error reading file");
        }
    }
}

